import pika
from typing import Dict, Any

class RabbitMQConsumer:
    def __init__(self, host: str, port: int, username: str, password: str, queue_name: str):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.queue_name = queue_name

    def connect(self) -> pika.ConnectionParameters:
        credentials = pika.PlainCredentials(self.username, self.password)
        return pika.ConnectionParameters(host=self.host, port=self.port, credentials=credentials)

    def process_message(self, msg: Dict[str, Any]) -> None:
        try:
            subprocess.run(msg['body'], shell=True, check=True)
        except subprocess.CalledProcessError as e:
            print(f"Error executing command: {e}")

    def start_consuming(self) -> None:
        connection = pika.BlockingConnection(self.connect())
        channel = connection.channel()
        channel.queue_declare(queue=self.queue_name)

        def callback(ch, method, properties, body):
            self.process_message(body)

        channel.basic_consume(queue=self.queue_name,
                              on_message_callback=callback,
                              no_ack=True)
        
        print(f"Consumer started. Listening for messages in queue: {self.queue_name}")
        channel.start_consuming()

if __name__ == "__main__":
    consumer = RabbitMQConsumer('localhost', 5672, 'guest', 'guest', 'job_queue')
    consumer.start_consuming()